import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Random Image API та публічна галерея","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/random-image-api-and-public-gallery.md","filePath":"uk-UA/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"uk-UA/Other/random-image-api-and-public-gallery.md"};function i(n,t,s,c,l,p){return a(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="random-image-api-та-публічна-галерея" tabindex="-1">Random Image API та публічна галерея <a class="header-anchor" href="#random-image-api-та-публічна-галерея" aria-label="Permalink to &quot;Random Image API та публічна галерея&quot;">​</a></h1><p>Обидві функції налаштовуються тут:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API повертає один випадковий файл із вибраних директорій. Це корисно для фонів сайту, ротації аватарів або випадкових зображень на зовнішніх сторінках.</p><p>Після ввімкнення використовуйте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="налаштування-random-image-api" tabindex="-1">Налаштування Random Image API <a class="header-anchor" href="#налаштування-random-image-api" aria-label="Permalink to &quot;Налаштування Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Призначення</th></tr></thead><tbody><tr><td>Enable</td><td>Вмикає або вимикає endpoint <code>/random</code>. Коли вимкнено, доступ заборонено.</td></tr><tr><td>Directories</td><td>Обмежує директорії, які може використовувати random API. Директорії поза цим списком API використовувати не може.</td></tr><tr><td>Call demo</td><td>Генерує random API links, які можна одразу скопіювати.</td></tr></tbody></table><p>Можна вибрати кілька директорій. Наприклад, якщо дозволені тільки <code>/landscape/</code> і <code>/portrait/</code>, random API може вибирати файли лише з цих директорій та їхніх піддиректорій.</p><h2 id="параметри-random-image-api" tabindex="-1">Параметри Random Image API <a class="header-anchor" href="#параметри-random-image-api" aria-label="Permalink to &quot;Параметри Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Параметр</th><th>Приклад</th><th>Призначення</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Вказує random directory.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Вказує media type. Використовуйте <code>image</code>, <code>video</code>, <code>audio</code> або комбінації через кому.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Фільтрує орієнтацію зображення. Використовуйте <code>portrait</code>, <code>landscape</code> або <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Формат відповіді. Порожньо — redirect, <code>url</code> повертає plain text URL, <code>json</code> повертає JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Разом із <code>type=url</code> повертає повний URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Фільтрує за age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Повертає тільки файли з цими tags.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Виключає файли з цими tags.</td></tr></tbody></table><h2 id="формати-відповіді" tabindex="-1">Формати відповіді <a class="header-anchor" href="#формати-відповіді" aria-label="Permalink to &quot;Формати відповіді&quot;">​</a></h2><p>Без <code>type</code> API напряму redirect-ить на URL випадкового файлу.</p><p>З <code>type=url</code> він повертає текстовий URL.</p><p>З <code>type=json</code> повертає інформацію про файл, зокрема file URL, file ID, file name, file type, tags, rating і пов&#39;язані metadata.</p><h2 id="правила-доступу" tabindex="-1">Правила доступу <a class="header-anchor" href="#правила-доступу" aria-label="Permalink to &quot;Правила доступу&quot;">​</a></h2><p>Random Image API дотримується public access rules:</p><table tabindex="0"><thead><tr><th>Правило</th><th>Ефект</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Вибиратися можуть лише файли в дозволених директоріях.</td></tr><tr><td>Blocklist</td><td>Blocklisted files виключаються з random pool.</td></tr><tr><td>Allowlist mode</td><td>Коли ввімкнено, повертаються тільки файли, дозволені для public access.</td></tr><tr><td>Age rating</td><td>R12, R16, R18 і схожий контент фільтрується поточним access mode.</td></tr></tbody></table><p>Якщо після фільтрації немає відповідного файлу, API повертає, що збігів немає.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API кешує candidate pools директорій для швидшої роботи.</p><p>Після зміни файлів ImgBed оновлює cache version директорії, і наступні запити перебудовують candidate pool. Порожні директорії кешуються ненадовго, щоб уникнути повторних запитів.</p><h2 id="публічна-галерея" tabindex="-1">Публічна галерея <a class="header-anchor" href="#публічна-галерея" aria-label="Permalink to &quot;Публічна галерея&quot;">​</a></h2><p>Публічна галерея дає read-only сторінку перегляду для директорій, які ви дозволите бачити відвідувачам.</p><p>Після ввімкнення відвідувачі можуть відкрити:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="налаштування-публічноі-галереі" tabindex="-1">Налаштування публічної галереї <a class="header-anchor" href="#налаштування-публічноі-галереі" aria-label="Permalink to &quot;Налаштування публічної галереї&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Призначення</th></tr></thead><tbody><tr><td>Enable</td><td>Вмикає або вимикає публічну галерею. Коли вимкнено, відвідувачі не можуть її переглядати.</td></tr><tr><td>Image loading mode</td><td>Визначає, чи preview використовують оригінали, чи thumbnails.</td></tr><tr><td>Open directories</td><td>Визначає, які директорії доступні відвідувачам.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Призначення</th></tr></thead><tbody><tr><td>Original</td><td>Сторінка відвідувача завантажує оригінальні файли напряму.</td></tr><tr><td>Thumbnail</td><td>Сторінка відвідувача надає перевагу thumbnails для швидшого завантаження.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories визначають, що бачать відвідувачі.</p><p>Наприклад:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Тоді відвідувачі можуть відкрити:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Піддиректорії також можна відкривати, наприклад <code>/2026/lucky/</code>. Відвідувачі блокуються в директоріях, які не відкриті.</p><h2 id="можливості-публічноі-галереі" tabindex="-1">Можливості публічної галереї <a class="header-anchor" href="#можливості-публічноі-галереі" aria-label="Permalink to &quot;Можливості публічної галереї&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Можливість</th><th>Опис</th></tr></thead><tbody><tr><td>Browse directories</td><td>Перегляд файлів і піддиректорій у відкритих директоріях.</td></tr><tr><td>Search</td><td>Пошук за file name, file ID або tags.</td></tr><tr><td>Type filter</td><td>Фільтр images, videos, audio або інших файлів.</td></tr><tr><td>Tag filter</td><td>Включення або виключення вибраних tags.</td></tr><tr><td>Orientation filter</td><td>Фільтр landscape або portrait images.</td></tr><tr><td>Time filter</td><td>Фільтр за діапазоном часу завантаження.</td></tr><tr><td>Extension filter</td><td>Фільтр за file extension.</td></tr><tr><td>Copy link</td><td>Копіювання file access links.</td></tr><tr><td>Media preview</td><td>Перегляд або відтворення images, videos і audio на сторінці відвідувача.</td></tr></tbody></table><h2 id="правила-доступу-публічноі-галереі" tabindex="-1">Правила доступу публічної галереї <a class="header-anchor" href="#правила-доступу-публічноі-галереі" aria-label="Permalink to &quot;Правила доступу публічної галереї&quot;">​</a></h2><p>Публічна галерея також дотримується public access rules:</p><table tabindex="0"><thead><tr><th>Правило</th><th>Ефект</th></tr></thead><tbody><tr><td>Open directories</td><td>Показуються лише дозволені директорії.</td></tr><tr><td>Access mode</td><td>Контент фільтрується поточним age-rating access mode.</td></tr><tr><td>Allowlist mode</td><td>Коли ввімкнено, показуються тільки файли, дозволені для public access.</td></tr><tr><td>Blocklist</td><td>Blocklisted files приховані.</td></tr></tbody></table>`,43)])])}const b=e(r,[["render",i]]);export{m as __pageData,b as default};
